// Format HUBEX alert event for email
const event = $input.item.json;

const severity = event.data?.severity || 'info';
const severityEmoji = {
  critical: '🔴',
  warning: '🟡',
  info: '🔵'
}[severity] || '⚪';

const deviceName = event.data?.device_name || event.data?.device_uid || 'Unknown Device';
const alertTitle = event.data?.title || event.event || 'HUBEX Alert';
const alertMessage = event.data?.message || JSON.stringify(event.data, null, 2);
const timestamp = event.timestamp || new Date().toISOString();

return {
  json: {
    subject: `${severityEmoji} HUBEX Alert: ${alertTitle}`,
    htmlBody: `
      <div style="font-family: -apple-system, sans-serif; max-width: 600px; margin: 0 auto;">
        <div style="background: #111110; padding: 20px; border-radius: 12px 12px 0 0;">
          <h2 style="color: #F5A623; margin: 0;">HUBEX Alert</h2>
        </div>
        <div style="background: #1a1a19; padding: 20px; border: 1px solid #333;">
          <table style="width: 100%; border-collapse: collapse; color: #e0e0e0;">
            <tr><td style="padding: 8px 0; color: #888;">Event</td><td style="padding: 8px 0;">${event.event}</td></tr>
            <tr><td style="padding: 8px 0; color: #888;">Severity</td><td style="padding: 8px 0;">${severityEmoji} ${severity}</td></tr>
            <tr><td style="padding: 8px 0; color: #888;">Device</td><td style="padding: 8px 0;">${deviceName}</td></tr>
            <tr><td style="padding: 8px 0; color: #888;">Time</td><td style="padding: 8px 0;">${timestamp}</td></tr>
            <tr><td style="padding: 8px 0; color: #888;">Message</td><td style="padding: 8px 0;">${alertMessage}</td></tr>
          </table>
        </div>
        <div style="background: #111110; padding: 12px 20px; border-radius: 0 0 12px 12px; text-align: center;">
          <a href="http://localhost/alerts" style="color: #2DD4BF; text-decoration: none;">Open HUBEX Dashboard</a>
        </div>
      </div>
    `,
    textBody: `HUBEX Alert: ${alertTitle}\n\nEvent: ${event.event}\nSeverity: ${severity}\nDevice: ${deviceName}\nTime: ${timestamp}\nMessage: ${alertMessage}`,
    eventId: event.event_id,
    stream: event.stream
  }
};
